# setup_kardex_fix.ps1 - Kardex con exportacion y filtros

Write-Host "Actualizando KardexTab..." -ForegroundColor Cyan

$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
$dir = Split-Path "src\modules\inventory\pages\tabs\KardexTab.tsx" -Parent
if ($dir) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\modules\inventory\pages\tabs\KardexTab.tsx", $text, [System.Text.Encoding]::UTF8)

Write-Host "KardexTab actualizado!" -ForegroundColor Green
